const API_BASE = (process.env.REACT_APP_API_URL || 'http://localhost:8080').replace(/\/$/, '');

async function handleResponse(res) {
	if (!res.ok) {
		const text = await res.text();
		let msg = text;
		try { msg = JSON.parse(text).message || JSON.parse(text); } catch {}
		throw new Error(msg || res.statusText);
	}
	return res.status === 204 ? null : res.json();
}

// export getAll with optional AbortSignal
export async function getAll(options = {}) {
	const { signal } = options;
	const res = await fetch(`${API_BASE}/robots`, { signal });
	return handleResponse(res);
}

// helper to build full image URL
export function getImageUrl(imgPath = '') {
	if (!imgPath) return '';
	return `${API_BASE}/${imgPath.replace(/^\/+/, '')}`;
}

// new: get single robot by id
export async function getById(id, options = {}) {
	const { signal } = options;
	const res = await fetch(`${API_BASE}/robots/${id}`, { signal });
	return handleResponse(res);
}

export default { getAll, getImageUrl, getById };
